package com.paymentchange.customer.controller;

import com.paymentchange.customer.entities.Customer;
import com.paymentchange.customer.repositories.CustomerRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.List;

@RestController
@RequestMapping("/customer")
public class CustomerRestController {

    @Autowired
    private CustomerRepository customerRepository;

    @GetMapping
    public List<Customer> findAll() {
        return customerRepository.findAll();
    }

    @PostMapping
    public ResponseEntity<Customer> create(@RequestBody Customer input) {
        Customer saved = customerRepository.save(input);
        return ResponseEntity.ok(saved);
    }
}
